mapper.select:
SELECT UserID, UserPW, UserName, LogInDate, UseYn
FROM ComMember
WHERE UserID = #{userId}
  AND UserPW = #{userPw}
  AND UseYn = 'Y'

mapper.update:
UPDATE ComMember
SET LogInDate = #{loginDate}
WHERE UserID = #{userId}

mapper.select:
SELECT COUNT(1)
FROM ComMember
WHERE UserID = #{userId}

mapper.insert:
INSERT INTO ComMember (
	UserID, UserPW, UserName, InsertDate, InsertUserID, UseYn
) VALUES (
	#{userId},
	#{userPw},
	#{userName},
	#{insertDate},
	#{insertUserId},
	#{useYn}
)
